// filter_audio.c - بناء graph فلاتر صوتي وتطبيقها على frames
#include <libavfilter/avfilter.h>
#include <libavfilter/buffersrc.h>
#include <libavfilter/buffersink.h>
#include <stdio.h>

int main(void) {
    // بناء graph: abuffer -> volume -> aformat -> abuffersink
    AVFilterGraph *graph = avfilter_graph_alloc();
    int ret = avfilter_graph_parse_ptr(graph,
        "abuffer=time_base=1/44100:sample_rate=44100:channel_layout=stereo"
        "[volume=1.5]"
        "[aformat=sample_fmts=flt:sample_rate=44100]"
        "[abuffersink]",
        NULL);
    if (ret < 0) {
        fprintf(stderr, "فشل بناء graph\n");
        return 1;
    }
    avfilter_graph_config(graph, NULL);

    // الآن يمكنك تمرير frames عبر الـ graph
    // av_buffersrc_add_frame() -> av_buffersink_get_frame()
    printf("Graph جاهز: abuffer -> volume -> aformat -> abuffersink\n");

    avfilter_graph_free(&graph);
    return 0;
}

